// 三载体一致:jsDelivr 把该 CommonJS 包转换成 ESM,使用具名 constructor
import { diff_match_patch } from 'https://cdn.jsdelivr.net/npm/diff-match-patch@1/+esm';
const dmp = new diff_match_patch(); if (data.timeoutSeconds != null) dmp.Diff_Timeout = data.timeoutSeconds;
const diffs = dmp.diff_main(data.oldText, data.newText);
if ((data.cleanup ?? 'semantic') === 'semantic') dmp.diff_cleanupSemantic(diffs);
else if (data.cleanup === 'efficiency') dmp.diff_cleanupEfficiency(diffs);
const patches = dmp.patch_make(data.oldText, diffs);
